// NewClient returns *argo.Client using MCP-backed endpoints.
func NewClient(scheme string, host string, doer goahttp.Doer, enc func(*http.Request) goahttp.Encoder, dec func(*http.Response) goahttp.Decoder, restore bool) *argo.Client {
	e := NewEndpoints(scheme, host, doer, enc, dec, restore)
	return argo.NewClient(e.ListWorkflows, e.GetWorkflow, e.GetWorkflowLogs, e.TerminateWorkflow, e.RetryWorkflow, e.ListCronWorkflows, e.GetCronWorkflow, e.GetCronHistory, e.ToggleCronSuspension, e.ListWorkflowTemplates, e.GetWorkflowTemplate, e.ListClusterWorkflowTemplates, e.GetClusterWorkflowTemplate)
}
